            migrationBuilder.Sql(@$"UPDATE data.general_gender_measures SET description = 'Allgemeine Massnahme EDI: Das Departement hat in den letzten Jahren verschiedene Sensibilisierungsmassnahmen getroffen. Im Rahmen von Sitzungen auf allen Ebenen wurden die Ämter auf die Vorgaben hingewiesen. Zudem wurden sie sowie die Präsidien beauftragt, die Suche nach möglichen Kandidatinnen und Kandidaten im Hinblick auf die Gesamterneuerungswahlen frühzeitig in Angriff zu nehmen mit dem Ziel, die Sprachen- und Geschlechtervertretung zu verbessern.' WHERE id = '2FF4DD55-B41F-4476-B32D-D2A1B900E1D4'");
            migrationBuilder.Sql(@$"UPDATE data.general_gender_measures SET description = 'Allgemeine Massnahme EJPD: Frühzeitige Sensibilisierung der Kommissionen, dass im Hinblick auf die GEW die Vorgabe wenn immer möglich eingehalten oder verbessert werden soll.' WHERE id = '432D1B9D-F262-446F-AA84-A00C9593FDE2'");
            migrationBuilder.Sql(@$"UPDATE data.general_gender_measures SET description = 'Allgemeine Massnahme VBS: Schreiben GS an die Kommissionspräsidien und die zuständigen Verwaltungseinheiten mit der Aufforderung, der Verbesserung der Vertretung der Frauen und der lateinischen Sprachgemeinschaften hohe Priorität einzuräumen und im Falle von Vakanzen die Suche nach geeigneten Kandidatinnen' WHERE id = '764DAA01-5496-4B37-9E4F-A0BFB1D85C80'");
            migrationBuilder.Sql(@$"UPDATE data.general_gender_measures SET description = 'Allgemeine Massnahmen EFD: Auf departementaler Ebene wurde ein Massnahmenkatalog bezugnehmend auf verschiedene Handlungsfelder (Kaderrekrutierung, Rekrutierungsprozess, Evaluation Sprachenkompetenz) erarbeitet und den HR-Leitenden der Verwaltungseinheiten abgegeben. Sensibilisierung der APK-Präsidien in Bezug auf den Nachzug geeigneter Kandidatinnen (gezielte Förderung und Ausbildung) sowie Information der Öffentlichkeit über bevorstehende Vakanzen. Durch die APK-Präsidien: bewusst frühzeitige Lancierung eines Nachfolgeprozesses um weibliche Fachpersonen finden und evaluieren zu können; dabei bewusste und aktive Nutzung bestehender interner und externer Netzwerke in den einzelnen Fachgebieten in der italienischen und französischen Schweiz.' WHERE id = '0DFC74EB-3E3B-4D44-B469-DFCCA479FE2C'");
            migrationBuilder.Sql(@$"UPDATE data.general_gender_measures SET description = '-' WHERE id = 'C2577849-38AC-4CBD-AD49-5E5847E6861B'");
            migrationBuilder.Sql(@$"UPDATE data.general_gender_measures SET description = 'Allgemeine Massnahme UVEK: Im Hinblick auf die anstehenden Gesamterneuerungswahlen hat das UVEK die für die ausserparlamentarischen Kommissionen zuständigen Stellen aufgefordert, bei der Zusammensetzung der Kommissionen der Erfüllung der Vorgaben des Bundes an die Geschlechter- und Sprachgemeinschaften hohe Priorität einzuräumen. Dabei wurde auch explizit auf den Entscheid des Bundesrates vom 23. November 2022 verwiesen, wonach die Geschlechterquoten auf 40% erhöht wurden. Ebenso wurde betont, dass allfällige Abweichungen von den Vorgaben zu begründen sind.' WHERE id = 'E03E6C54-4B7E-4E4D-B4C3-DB925CDB66AF'");

            migrationBuilder.Sql(@$"UPDATE data.general_language_measures SET description = 'Allgemeine Massnahme EDI: Das Departement hat in den letzten Jahren verschiedene Sensibilisierungsmassnahmen getroffen. Im Rahmen von Sitzungen auf allen Ebenen wurden die Ämter auf die Vorgaben hingewiesen. Zudem wurden sie sowie die Präsidien beauftragt, die Suche nach möglichen Kandidatinnen und Kandidaten im Hinblick auf die Gesamterneuerungswahlen frühzeitig in Angriff zu nehmen mit dem Ziel, die Sprachen- und Geschlechtervertretung zu verbessern.' WHERE id = 'DA7526B2-A1F7-4678-97B1-868DF650FF95'");
            migrationBuilder.Sql(@$"UPDATE data.general_language_measures SET description = 'Allgemeine Massnahme EJPD: Frühzeitige Sensibilisierung der Kommissionen, dass im Hinblick auf die GEW die Vorgabe wenn immer möglich eingehalten oder verbessert werden soll.' WHERE id = 'F01ECE15-82FE-42D7-94AB-0972ABAE4121'");
            migrationBuilder.Sql(@$"UPDATE data.general_language_measures SET description = 'Allgemeine Massnahme VBS: Schreiben GS an die Kommissionspräsidien und die zuständigen Verwaltungseinheiten mit der Aufforderung, der Verbesserung der Vertretung der Frauen und der lateinischen Sprachgemeinschaften hohe Priorität einzuräumen und im Falle von Vakanzen die Suche nach geeigneten Kandidatinnen' WHERE id = '708F216D-543E-4771-86EA-FA3D4675C4F9'");
            migrationBuilder.Sql(@$"UPDATE data.general_language_measures SET description = 'Allgemeine Massnahmen EFD: Sensibilisierung der APK-Präsidien in Bezug auf den Nachzug geeigneter Kandidatinnen (gezielte Förderung und Ausbildung) sowie Information der Öffentlichkeit über bevorstehende Vakanzen. Durch die APK-Präsidien: bewusst frühzeitige Lancierung eines Nachfolgeprozesses um weibliche Fachpersonen finden und evaluieren zu können; dabei bewusste und aktive Nutzung bestehender interner und externer Netzwerke in den einzelnen Fachgebieten in der italienischen und französischen Schweiz. Allgemein wurde auf departementaler Ebene ein Massnahmenkatalog bezugnehmend auf verschiedene Handlungsfelder (Kaderrekrutierung, Rekrutierungsprozess, Evaluation Sprachenkompetenz) erarbeitet und den HR-Leitenden der Verwaltungseinheiten abgegeben. Die Umsetzung wurde anlässlich eines EFD-internen Massnahmenreportings evaluiert und in einem Katalog zusammengefasst. Es gilt ein Minimalstandard gemäss Art. 8 SpV (Sprachenanforderungen) wie auch Art. 8c und Art. 8cbis RVOV (Vertretung der Geschlechter und der Sprachgemeinschaften), welcher durch das DLZ Pers EFD oder das HR EFD sichergestellt wird.' WHERE id = '0F71EF59-B2E8-4E94-985C-E59137E9C275'");
